// Add 40 generic players to ensure the pool is large enough for 6 teams x 21 players
for(let i=1; i<=60; i++) {
    const isForeign = i % 3 === 0;
    const nats = ['England', 'Australia', 'South Africa', 'New Zealand', 'West Indies', 'Sri Lanka'];
    playersRaw.push({
        id: `g${i}`,
        name: `Player ${i}`,
        nationality: isForeign ? nats[i % nats.length] : 'Local',
        role: i % 5 === 0 ? PlayerRole.WICKET_KEEPER : i % 4 === 0 ? PlayerRole.ALL_ROUNDER : i % 3 === 0 ? PlayerRole.SPIN_BOWLER : i % 2 === 0 ? PlayerRole.FAST_BOWLER : PlayerRole.BATSMAN,
        battingSkill: 40 + Math.floor(Math.random() * 40),
        secondarySkill: 10 + Math.floor(Math.random() * 70),
        style: Math.random() > 0.6 ? 'A' : Math.random() > 0.3 ? 'N' : 'D',
        isOpener: Math.random() > 0.8,
        isForeign
    });
}

