export const aggregateStats = (player: Player, formats: Format[]): PlayerStats => {
    const total = generateSingleFormatInitialStats();
    formats.forEach(f => {
        const s = player.stats[f];
        if (s) {
            total.matches += s.matches;
            total.runs += s.runs;
            total.ballsFaced += s.ballsFaced;
            total.dismissals += s.dismissals;
            if (s.highestScore > total.highestScore) total.highestScore = s.highestScore;
            total.hundreds += s.hundreds;
            total.fifties += s.fifties;
            total.thirties += s.thirties;
            total.fours += s.fours;
            total.sixes += s.sixes;
            total.wickets += s.wickets;
            total.ballsBowled += s.ballsBowled;
            total.runsConceded += s.runsConceded;
            total.threeWicketHauls += s.threeWicketHauls;
            total.fiveWicketHauls += s.fiveWicketHauls;
            total.manOfTheMatchAwards += s.manOfTheMatchAwards;
            if (s.bestBowlingWickets > total.bestBowlingWickets || (s.bestBowlingWickets === total.bestBowlingWickets && s.bestBowlingRuns < total.bestBowlingRuns)) {
                total.bestBowlingWickets = s.bestBowlingWickets;
                total.bestBowlingRuns = s.bestBowlingRuns;
                total.bestBowling = s.bestBowling;
            }
        }
    });
    total.average = total.dismissals > 0 ? total.runs / total.dismissals : total.runs;
    total.strikeRate = total.ballsFaced > 0 ? (total.runs / total.ballsFaced) * 100 : 0;
    total.bowlingAverage = total.wickets > 0 ? total.runsConceded / total.wickets : 0; 
    total.economy = total.ballsBowled > 0 ? (total.runsConceded / total.ballsBowled) * 6 : 0;
    return total;
};

export const generateLeagueSchedule = (teams: Team[], format: Format, doubleRoundRobin: boolean = true): Match[] => {
    const matches: Match[] = [];
    if (teams.length < 2) return [];
    const pairs: [Team, Team][] = [];
    for(let i=0; i<teams.length; i++) {
        for(let j=i+1; j<teams.length; j++) {
            pairs.push([teams[i], teams[j]]);
        }
    }
    let matchCounter = 1;
    pairs.forEach(([tA, tB]) => {
        matches.push({ matchNumber: matchCounter++, teamA: tA.name, teamAId: tA.id, vs: 'vs', teamB: tB.name, teamBId: tB.id, date: `Day ${matchCounter}`, group: 'Round-Robin' });
    });
    if (doubleRoundRobin) {
        pairs.forEach(([tA, tB]) => {
            matches.push({ matchNumber: matchCounter++, teamA: tB.name, teamAId: tB.id, vs: 'vs', teamB: tA.name, teamBId: tA.id, date: `Day ${matchCounter}`, group: 'Round-Robin' });
        });
    }
    matches.push({ matchNumber: 'SF1', teamA: '1st', vs: 'vs', teamB: '4th', date: 'SF Day', group: 'Semi-Finals' });
    matches.push({ matchNumber: 'SF2', teamA: '2nd', vs: 'vs', teamB: '3rd', date: 'SF Day', group: 'Semi-Finals' });
    matches.push({ matchNumber: 'Final', teamA: 'SF1 Winner', vs: 'vs', teamB: 'SF2 Winner', date: 'Finals Day', group: 'Final' });
    return matches;
};

export const negotiateSponsorships = (popularity: number): Record<Format, Sponsorship> => {
    const newSponsorships: any = {};
    Object.values(Format).forEach(f => {
        newSponsorships[f] = { sponsorName: BRANDS[0].name, tournamentName: "Championship", logoColor: "text-teal-500", tournamentLogo: TOURNAMENT_LOGOS[0].svg, tvChannel: TV_CHANNELS[0].name, tvLogo: TV_CHANNELS[0].logo };
    });
    return newSponsorships;
};

export const calculatePlayerRankings = (players: Player[], format: Format, teams: Team[]) => {
    const scoredPlayers = players.map(p => ({ player: p, points: p.stats[format]?.runs || 0, teamName: "Team" }));
    return { batters: scoredPlayers, bowlers: scoredPlayers, allRounders: scoredPlayers };
};

import React, { useState, useEffect } from 'react';
import { AppState, GameData, Team, Format, MatchResult } from './types';
import { PLAYERS, TEAMS, GROUNDS, PRE_BUILT_SQUADS, INITIAL_SPONSORSHIPS, INITIAL_NEWS } from './data';
import { LoadingSpinner, generateLeagueSchedule } from './utils';

// Components
import MainMenu from './components/MainMenu';
import TeamSelection from './components/TeamSelection';
import CareerHub from './components/CareerHub';
import AuctionRoom from './components/AuctionRoom';

export const MAX_SQUAD_SIZE = 21;
export const MIN_LOCAL_PLAYERS = 12;
export const MAX_FOREIGN_PLAYERS = 8;

export const App = () => {
  const [appState, setAppState] = useState<AppState>('MAIN_MENU');
  const [gameData, setGameData] = useState<GameData | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [theme, setTheme] = useState<'light' | 'dark'>('dark');
  const [feedbackMessage, setFeedbackMessage] = useState<{ text: string; type: 'success' | 'error' } | null>(null);
  const [hasSaveData, setHasSaveData] = useState(false);

  useEffect(() => {
    const savedTheme = localStorage.getItem('cricketManagerTheme') || 'dark';
    setTheme(savedTheme as 'light' | 'dark');
    const savedGame = localStorage.getItem('cricketManagerSave');
    if (savedGame) {
        setHasSaveData(true);
    }
    setIsLoading(false);
  }, []);

  useEffect(() => {
    if (theme === 'light') document.documentElement.classList.remove('dark');
    else document.documentElement.classList.add('dark');
    localStorage.setItem('cricketManagerTheme', theme);
  }, [theme]);

  useEffect(() => {
    if (gameData && !isLoading) {
      localStorage.setItem('cricketManagerSave', JSON.stringify(gameData));
      setHasSaveData(true);
    }
  }, [gameData, isLoading]);

  const showFeedback = (text: string, type: 'success' | 'error' = 'success') => {
    setFeedbackMessage({ text, type });
    setTimeout(() => setFeedbackMessage(null), 2500);
  };

  const handleStartNewGame = () => {
    if (hasSaveData && !window.confirm("Starting a new game will overwrite progress. Continue?")) return;
    setAppState('TEAM_SELECTION');
  };

  const resumeGame = () => {
    const savedGame = localStorage.getItem('cricketManagerSave');
    if (savedGame) {
        try {
            setGameData(JSON.parse(savedGame));
            setAppState('CAREER_HUB');
            showFeedback("Game Resumed!", "success");
        } catch(e) {
            localStorage.removeItem('cricketManagerSave');
            setHasSaveData(false);
            showFeedback("Save data corrupt.", "error");
        }
    }
  };

  const initializeNewGame = (userTeamId: string) => {
    setIsLoading(true);
    const usedPlayerIds = new Set<string>();

    const initialTeams: Team[] = TEAMS.map(teamData => {
        let squad = [];
        const preBuiltIds = PRE_BUILT_SQUADS[teamData.id] || [];
        preBuiltIds.forEach(pid => {
            const p = PLAYERS.find(pl => pl.id === pid);
            if (p && !usedPlayerIds.has(pid)) {
                squad.push(JSON.parse(JSON.stringify(p)));
                usedPlayerIds.add(pid);
            }
        });
        return { id: teamData.id, name: teamData.name, squad, captains: {}, purse: 50.0 };
    });

    const initialStandings = (teams: Team[]) => teams.map(team => ({ 
        teamId: team.id, teamName: team.name, played: 0, won: 0, lost: 0, drawn: 0, points: 0, netRunRate: 0, runsFor: 0, runsAgainst: 0 
    }));

    const schedules = {
        [Format.T20]: generateLeagueSchedule(initialTeams, Format.T20, true),
        [Format.ODI]: generateLeagueSchedule(initialTeams, Format.ODI, true),
        [Format.FIRST_CLASS]: generateLeagueSchedule(initialTeams, Format.FIRST_CLASS, true),
    };

    const newGameData: GameData = {
      userTeamId,
      teams: initialTeams,
      grounds: [...GROUNDS],
      allTeamsData: [...TEAMS],
      allPlayers: [...PLAYERS],
      schedule: schedules,
      currentMatchIndex: { [Format.T20]: 0, [Format.ODI]: 0, [Format.FIRST_CLASS]: 0 },
      standings: { [Format.T20]: initialStandings(initialTeams), [Format.ODI]: initialStandings(initialTeams), [Format.FIRST_CLASS]: initialStandings(initialTeams) },
      matchResults: { [Format.T20]: [], [Format.ODI]: [], [Format.FIRST_CLASS]: [] },
      playingXIs: {},
      currentSeason: 1,
      currentFormat: Format.T20, 
      awardsHistory: [],
      records: { batterVsBowler: [], teamVsTeam: [], playerVsTeam: [] },
      promotionHistory: [],
      popularity: 50,
      sponsorships: INITIAL_SPONSORSHIPS,
      news: INITIAL_NEWS,
      activeMatch: null,
      settings: { isDoubleRoundRobin: true }
    };
    setGameData(newGameData);
    setAppState('AUCTION');
    setIsLoading(false);
  };

  const handleAuctionComplete = (finalTeams: Team[]) => {
      setGameData(prev => prev ? { ...prev, teams: finalTeams } : null);
      setAppState('CAREER_HUB');
      showFeedback("Draft Room Closed!", "success");
  };

  const renderContent = () => {
    if (isLoading) return <div className="bg-white dark:bg-gray-900 h-full flex items-center justify-center"><LoadingSpinner /></div>;
    switch(appState) {
        case 'MAIN_MENU': return <MainMenu onStartNewGame={handleStartNewGame} onResumeGame={resumeGame} hasSaveData={hasSaveData} />;
        case 'TEAM_SELECTION': return <TeamSelection onTeamSelected={initializeNewGame} theme={theme} />;
        case 'AUCTION': return gameData ? <AuctionRoom gameData={gameData} onAuctionComplete={handleAuctionComplete} /> : null;
        case 'CAREER_HUB': return gameData ? <CareerHub gameData={gameData} setGameData={setGameData} onResetGame={() => setAppState('MAIN_MENU')} theme={theme} setTheme={setTheme} saveGame={() => {}} loadGame={() => {}} showFeedback={showFeedback} /> : null;
        default: return null;
    }
  }

  return (
    <div className="bg-gray-100 dark:bg-gray-900 min-h-screen flex items-center justify-center font-sans">
      <div className="w-full max-w-md h-screen max-h-[932px] bg-gray-50 dark:bg-[#2C3531] border-4 border-gray-300 dark:border-gray-700 rounded-[60px] shadow-2xl overflow-hidden relative text-gray-900 dark:text-gray-200 flex flex-col">
        {renderContent()}
        {feedbackMessage && (
            <div className={`absolute bottom-28 left-1/2 -translate-x-1/2 px-4 py-2 rounded-lg z-50 shadow-lg text-white font-semibold ${feedbackMessage.type === 'success' ? 'bg-green-500' : 'bg-red-500'}`}>
                {feedbackMessage.text}
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { GameData, Player, PlayerRole } from '../types';
import { getRoleColor, getRoleFullName } from '../utils';
import { Icons } from './Icons';

interface PlayerDatabaseProps {
    gameData: GameData;
    onAddPlayer: () => void;
    onViewPlayer: (player: Player) => void;
}

const PlayerDatabase: React.FC<PlayerDatabaseProps> = ({ gameData, onAddPlayer, onViewPlayer }) => {
    const [searchTerm, setSearchTerm] = useState('');
    const [roleFilter, setRoleFilter] = useState<PlayerRole | 'ALL'>('ALL');
    const [natFilter, setNatFilter] = useState<string>('ALL');
    const [teamFilter, setTeamFilter] = useState<string>('ALL');

    const nationalities = useMemo(() => {
        const nats = new Set(gameData.allPlayers.map(p => p.nationality));
        return ['ALL', ...Array.from(nats).sort()];
    }, [gameData.allPlayers]);

    const teamsList = useMemo(() => {
        return ['ALL', 'Free Agent', ...gameData.teams.map(t => t.name).sort()];
    }, [gameData.teams]);

    const filteredPlayers = useMemo(() => {
        return gameData.allPlayers.filter(p => {
            const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase());
            const matchesRole = roleFilter === 'ALL' || p.role === roleFilter;
            const matchesNat = natFilter === 'ALL' || p.nationality === natFilter;

            const playerTeam = gameData.teams.find(t => t.squad.some(sp => sp.id === p.id))?.name || 'Free Agent';
            const matchesTeam = teamFilter === 'ALL' || playerTeam === teamFilter;

            return matchesSearch && matchesRole && matchesNat && matchesTeam;
        });
    }, [gameData.allPlayers, gameData.teams, searchTerm, roleFilter, natFilter, teamFilter]);

    return (
        <div className="h-full flex flex-col bg-slate-950 text-white">
            <header className="p-4 bg-slate-900 border-b border-slate-800">
                <div className="flex justify-between items-center mb-2">
                    <h2 className="text-xl font-black italic uppercase tracking-tighter text-teal-400">Registry ({filteredPlayers.length})</h2>
                    <button onClick={onAddPlayer} className="bg-pink-600 text-white p-1.5 rounded-full"><Icons.PlusCircle /></button>
                </div>

                <div className="space-y-2">
                    <input 
                        type="text" 
                        placeholder="Search player..." 
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full px-3 py-1.5 bg-slate-800 border border-slate-700 rounded-lg text-xs"
                    />

                    <div className="grid grid-cols-2 gap-2">
                        <select 
                            value={natFilter} 
                            onChange={(e) => setNatFilter(e.target.value)}
                            className="bg-slate-800 border border-slate-700 rounded px-2 py-1 text-[10px]"
                        >
