import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Player, Team, GameData, PlayerRole } from '../types';
import { getRoleColor, getRoleFullName } from '../utils';
import { Icons } from './Icons';

interface AuctionRoomProps {
    gameData: GameData;
    onAuctionComplete: (updatedTeams: Team[]) => void;
}

const STARTING_PURSE = 50.0;
const MAX_SQUAD_TOTAL = 21;
const MIN_LOCAL_PLAYERS = 12;
const MAX_FOREIGN_LIMIT = 8;

const AuctionRoom: React.FC<AuctionRoomProps> = ({ gameData, onAuctionComplete }) => {
    const [teams, setTeams] = useState<Team[]>(() => 
        gameData.teams.map(t => ({ ...t, squad: t.squad || [], purse: t.purse || STARTING_PURSE }))
    );

    const [activeOverlay, setActiveOverlay] = useState<'none' | 'franchises'>('none');
    const [currentPlayerIdx, setCurrentPlayerIdx] = useState(0);
    const [currentBid, setCurrentBid] = useState(0);
    const [highestBidderId, setHighestBidderId] = useState<string | null>(null);
    const [isAuctioning, setIsAuctioning] = useState(false);
    const [biddingLog, setBiddingLog] = useState<string[]>([]);
    const [auctionFinished, setAuctionFinished] = useState(false);

    const sortedPool = useMemo(() => {
        const retainedIds = new Set(teams.flatMap(t => t.squad.map(p => p.id)));
        return gameData.allPlayers
            .filter(pl => !retainedIds.has(pl.id))
            .sort((a, b) => Math.max(b.battingSkill, b.secondarySkill) - Math.max(a.battingSkill, a.secondarySkill));
    }, [gameData.allPlayers, teams]);

    const currentPlayer = sortedPool[currentPlayerIdx] || null;
    const userTeam = teams.find(t => t.id === gameData.userTeamId);

    const startNextPlayer = useCallback(() => {
        if (auctionFinished || currentPlayerIdx >= sortedPool.length) {
            setAuctionFinished(true);
            return;
        }
        const player = sortedPool[currentPlayerIdx];
        const bp = Math.max(player.battingSkill, player.secondarySkill) > 70 ? 2.0 : 1.0;
        setCurrentBid(bp);
        setHighestBidderId(null);
        setIsAuctioning(true);
        setBiddingLog(prev => [`Lot #${currentPlayerIdx + 1}: ${player.name} up for ${bp.toFixed(2)} Cr`, ...prev.slice(0, 5)]);
    }, [currentPlayerIdx, sortedPool, auctionFinished]);

    const handleUserBid = () => {
        if (!userTeam || !isAuctioning || !currentPlayer) return;

        const foreignCount = userTeam.squad.filter(p => p.isForeign).length;
        if (currentPlayer.isForeign && foreignCount >= MAX_FOREIGN_LIMIT) {
            alert("Foreign limit reached!");
            return;
        }
        if (userTeam.squad.length >= MAX_SQUAD_TOTAL) {
            alert("Squad full!");
            return;
        }

        const nextBid = Number((currentBid + 0.1).toFixed(2));
        if (userTeam.purse < nextBid) return;

        setCurrentBid(nextBid);
        setHighestBidderId(userTeam.id);
        setBiddingLog(prev => [`${userTeam.name} bids ${nextBid.toFixed(2)} Cr!`, ...prev.slice(0, 5)]);
    };

    useEffect(() => {
        if (!isAuctioning || !currentPlayer || auctionFinished) return;
        const timer = setTimeout(() => {
            const otherTeams = teams.filter(t => t.id !== highestBidderId && t.id !== gameData.userTeamId && t.purse >= (currentBid + 0.1) && t.squad.length < MAX_SQUAD_TOTAL);
            const bidder = otherTeams[Math.floor(Math.random() * otherTeams.length)];

            if (bidder && Math.random() > 0.4) {
                const nextBid = Number((currentBid + 0.1).toFixed(2));
                setCurrentBid(nextBid);
                setHighestBidderId(bidder.id);
                setBiddingLog(prev => [`${bidder.name} bids ${nextBid.toFixed(2)} Cr!`, ...prev.slice(0, 5)]);
            } else if (highestBidderId) {
                const winner = teams.find(t => t.id === highestBidderId);
                if (winner) {
                    setTeams(prev => prev.map(t => t.id === winner.id ? { ...t, purse: Number((t.purse - currentBid).toFixed(2)), squad: [...t.squad, currentPlayer] } : t));
                    setBiddingLog(prev => [`SOLD to ${winner.name} for ${currentBid.toFixed(2)} Cr`, ...prev]);
                }
                setIsAuctioning(false);
                setTimeout(() => setCurrentPlayerIdx(i => i + 1), 500);
            } else {
                setBiddingLog(prev => [`UNSOLD: ${currentPlayer.name}`, ...prev]);
                setIsAuctioning(false);
                setTimeout(() => setCurrentPlayerIdx(i => i + 1), 500);
            }
        }, 800);
        return () => clearTimeout(timer);
    }, [isAuctioning, currentBid, highestBidderId, currentPlayer, teams]);

    useEffect(() => {
        if (!isAuctioning && !auctionFinished) startNextPlayer();
    }, [currentPlayerIdx, isAuctioning, auctionFinished, startNextPlayer]);

    return (
        <div className="h-full flex flex-col bg-slate-950 text-white p-4">
            {auctionFinished ? (
                <div className="flex-1 flex flex-col items-center justify-center text-center">
                    <h2 className="text-3xl font-black italic uppercase text-teal-400 mb-4">Draft Complete</h2>
                    <p className="text-sm text-slate-400 mb-8">All squads finalized with Season 26 rules.</p>
                    <button onClick={() => onAuctionComplete(teams)} className="w-full bg-teal-500 py-4 rounded-xl font-bold uppercase italic">Enter Season</button>
                </div>
            ) : (
                <div className="flex-1 flex flex-col">
                    <div className="flex justify-between mb-4">
                        <span className="text-xl font-black text-teal-400">{userTeam?.purse.toFixed(2)} Cr</span>
                        <button onClick={() => setActiveOverlay('franchises')} className="text-xs font-bold uppercase underline">Franchises</button>
                    </div>
                    {currentPlayer && (
                        <div className="bg-slate-900 border border-slate-800 p-6 rounded-3xl text-center">
                            <h2 className="text-4xl font-black uppercase italic mb-2">{currentPlayer.name}</h2>
                            <p className={`text-xs font-bold uppercase mb-4 ${getRoleColor(currentPlayer.role)}`}>{getRoleFullName(currentPlayer.role)} {currentPlayer.isForeign ? '(F)' : ''}</p>
                            <div className="bg-black/50 p-4 rounded-xl mb-6">
                                <p className="text-[10px] text-slate-500 uppercase font-bold">Current Bid</p>
                                <p className="text-5xl font-black text-yellow-400">{currentBid.toFixed(2)} Cr</p>
                            </div>
                            <button 
                                onClick={handleUserBid}
                                disabled={highestBidderId === userTeam?.id || !isAuctioning}
                                className="w-full bg-teal-600 hover:bg-teal-500 py-4 rounded-xl text-xl font-black uppercase shadow-lg disabled:opacity-30"
                            >
                                BID {(currentBid + 0.1).toFixed(2)}
                            </button>
                        </div>
                    )}
                    <div className="mt-4 flex-1 bg-black p-3 rounded-lg font-mono text-[10px] text-slate-400 overflow-y-auto">
                        {biddingLog.map((l, i) => <p key={i}>{l}</p>)}
                    </div>
                </div>
            )}
        </div>
    );
};

export default AuctionRoom;

import React, { useCallback } from 'react';
import { GameData, Format, PlayerRole, MatchResult, Inning, BattingPerformance, BowlingPerformance, Team, Match, Player } from '../types';
import { PITCH_MODIFIERS, formatOvers, getPlayerById, generateAutoXI, getBatterTier, BATTING_PROFILES } from '../utils';

export const useSimulation = (gameData: GameData, setGameData: React.Dispatch<React.SetStateAction<GameData | null>>) => {
    const simulateInning = useCallback((battingTeam: Team, bowlingTeam: Team, format: Format, target: number | null, pitch: string, groundCode: string, inningNumber: number, allPlayers: Player[]): Inning => {
        const pitchMods = PITCH_MODIFIERS[pitch as keyof typeof PITCH_MODIFIERS] || PITCH_MODIFIERS["Balanced Sporting Pitch"];
        const formatMods = pitchMods[format] || { runRate: 1, wicketChance: 1 };

        const maxBalls = (format === Format.T20 ? 20 : format === Format.ODI ? 50 : 90) * 6;
        const bowlerLimit = (format === Format.T20 ? 4 : format === Format.ODI ? 10 : 30) * 6;

        let score = 0, wickets = 0, balls = 0;

        const battingLineup: BattingPerformance[] = battingTeam.squad.map(p => ({ 
            playerId: p.id, playerName: p.name, runs: 0, balls: 0, fours: 0, sixes: 0, isOut: false, dismissalText: 'not out', dismissal: { type: 'not out', bowlerId: '' } 
        }));

        const bowlingLineup = bowlingTeam.squad.filter(p => [PlayerRole.FAST_BOWLER, PlayerRole.SPIN_BOWLER, PlayerRole.ALL_ROUNDER].includes(p.role)).map(p => ({ 
            playerId: p.id, playerName: p.name, overs: '0.0', maidens: 0, runsConceded: 0, wickets: 0, ballsBowled: 0 
        }));

        let onStrikeIdx = 0, offStrikeIdx = 1, bowlerIdx = 0;

        while (balls < maxBalls && wickets < 10) {
            if (target && score > target) break;

            const striker = battingLineup[onStrikeIdx];
            const bowler = bowlingLineup[bowlerIdx];
            if (!striker || !bowler) break;

            const sDetails = getPlayerById(striker.playerId, allPlayers);
            const bDetails = getPlayerById(bowler.playerId, allPlayers);

            // Simple prob based simulation
            const skillDiff = (sDetails.battingSkill - bDetails.secondarySkill) / 100;
            const wktProb = (0.05 - skillDiff * 0.02) * formatMods.wicketChance;

            balls++;
            striker.balls++;
            bowler.ballsBowled++;

            if (Math.random() < wktProb) {
                wickets++;
                striker.isOut = true;
                striker.dismissalText = `b ${bowler.playerName}`;
                bowler.wickets++;
                onStrikeIdx = Math.max(onStrikeIdx, offStrikeIdx) + 1;
            } else {
                let runs = 0;
                const rRand = Math.random();
                if (rRand < 0.4) runs = 0;
                else if (rRand < 0.75) runs = 1;
                else if (rRand < 0.85) runs = 4;
                else if (rRand < 0.9) runs = 6;
                else runs = 2;

                striker.runs += runs;
                if (runs === 4) striker.fours++;
                if (runs === 6) striker.sixes++;
                score += runs;
                bowler.runsConceded += runs;
                if (runs % 2 !== 0) [onStrikeIdx, offStrikeIdx] = [offStrikeIdx, onStrikeIdx];
            }

            if (balls % 6 === 0) {
                [onStrikeIdx, offStrikeIdx] = [offStrikeIdx, onStrikeIdx];
                // Rotate bowler if limit reached
                if (bowler.ballsBowled >= bowlerLimit) {
                    bowlerIdx = (bowlerIdx + 1) % bowlingLineup.length;
                } else if (Math.random() > 0.7) {
                    bowlerIdx = (bowlerIdx + 1) % bowlingLineup.length;
                }
            }
        }

        return { 
            teamId: battingTeam.id, teamName: battingTeam.name, score, wickets, overs: formatOvers(balls), extras: 0,
            batting: battingLineup.slice(0, wickets + 2), bowling: bowlingLineup.map(b => ({...b, overs: formatOvers(b.ballsBowled)})) 
        };
    }, []);

    const runSimulationForCurrentFormat = useCallback((match: Match, gameData: GameData): MatchResult => {
        const teamA = gameData.teams.find(t => t.name === match.teamA)!;
        const teamB = gameData.teams.find(t => t.name === match.teamB)!;
        const ground = gameData.grounds[0];

        if (gameData.currentFormat === Format.FIRST_CLASS) {
            // Test Match generated logic
            const inn1 = simulateInning(teamA, teamB, Format.FIRST_CLASS, null, ground.pitch, ground.code, 1, gameData.allPlayers);
            const inn2 = simulateInning(teamB, teamA, Format.FIRST_CLASS, null, ground.pitch, ground.code, 2, gameData.allPlayers);
            const inn3 = simulateInning(teamA, teamB, Format.FIRST_CLASS, null, ground.pitch, ground.code, 3, gameData.allPlayers);
            const target = (inn1.score + inn3.score) - inn2.score + 1;
            const inn4 = simulateInning(teamB, teamA, Format.FIRST_CLASS, target, ground.pitch, ground.code, 4, gameData.allPlayers);

            const winnerId = inn4.score >= target ? teamB.id : (inn4.wickets === 10 ? teamA.id : null);
            return { matchNumber: match.matchNumber, winnerId, loserId: winnerId ? (winnerId === teamA.id ? teamB.id : teamA.id) : null, isDraw: !winnerId, summary: winnerId ? "Result achieved" : "Match Drawn", firstInning: inn1, secondInning: inn2, thirdInning: inn3, fourthInning: inn4, manOfTheMatch: { playerId: '', playerName: 'TBD', teamId: '', summary: '' } };
        } else {
            const inn1 = simulateInning(teamA, teamB, gameData.currentFormat, null, ground.pitch, ground.code, 1, gameData.allPlayers);
            const inn2 = simulateInning(teamB, teamA, gameData.currentFormat, inn1.score, ground.pitch, ground.code, 2, gameData.allPlayers);
            const winnerId = inn2.score > inn1.score ? teamB.id : (inn1.score > inn2.score ? teamA.id : null);
            return { matchNumber: match.matchNumber, winnerId, loserId: winnerId ? (winnerId === teamA.id ? teamB.id : teamA.id) : null, summary: winnerId ? "Result achieved" : "Match Tied", firstInning: inn1, secondInning: inn2, manOfTheMatch: { playerId: '', playerName: 'TBD', teamId: '', summary: '' } };
        }
    }, [simulateInning]);

    const updateStatsFromMatch = useCallback((result: MatchResult, format: Format, gameData: GameData): GameData => {
        const newData = JSON.parse(JSON.stringify(gameData));
        newData.matchResults[format].push(result);
        const sIdx = newData.standings[format].findIndex((s: any) => s.teamId === result.winnerId);
        if (sIdx !== -1) newData.standings[format][sIdx].won++;
        return newData;
    }, []);

    return { runSimulationForCurrentFormat, updateStatsFromMatch };
}

