import React, { useState, useMemo } from 'react';
import { GameData, Format, Player } from '../types';
import { aggregateStats } from '../utils';

interface StatsProps {
    gameData: GameData;
    viewPlayerProfile: (player: Player, format: Format) => void;
}

const Stats: React.FC<StatsProps> = ({ gameData, viewPlayerProfile }) => {
    const [selectedFormat, setSelectedFormat] = useState<Format>(gameData.currentFormat);
    const [tab, setTab] = useState<'runs' | 'wickets'>('runs');

    const leaderboard = useMemo(() => {
        return gameData.allPlayers
            .map(p => ({ ...p, stat: tab === 'runs' ? p.stats[selectedFormat].runs : p.stats[selectedFormat].wickets }))
            .filter(p => p.stat > 0)
            .sort((a, b) => b.stat - a.stat);
    }, [gameData.allPlayers, selectedFormat, tab]);

    return (
        <div className="p-4 h-full flex flex-col bg-slate-950 text-white">
            <h2 className="text-xl font-black italic uppercase tracking-tighter text-teal-400 mb-4">Leaderboards</h2>

            <div className="flex gap-1 overflow-x-auto pb-4 scrollbar-hide">
                {Object.values(Format).map(f => (
                    <button key={f} onClick={() => setSelectedFormat(f)} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase whitespace-nowrap border ${selectedFormat === f ? 'bg-teal-500 text-black' : 'bg-slate-900 border-slate-800'}`}>{f}</button>
                ))}
            </div>

            <div className="flex bg-slate-900 p-1 rounded-xl mb-4">
                <button onClick={() => setTab('runs')} className={`flex-1 py-2 rounded-lg text-[10px] font-black uppercase ${tab === 'runs' ? 'bg-slate-800 text-white' : 'text-slate-500'}`}>Top Batters</button>
                <button onClick={() => setTab('wickets')} className={`flex-1 py-2 rounded-lg text-[10px] font-black uppercase ${tab === 'wickets' ? 'bg-slate-800 text-white' : 'text-slate-500'}`}>Top Bowlers</button>
            </div>

            <div className="flex-1 overflow-y-auto space-y-1">
                {leaderboard.map((p, i) => (
                    <div key={p.id} onClick={() => viewPlayerProfile(p, selectedFormat)} className="bg-slate-900 p-3 rounded-xl border border-slate-800 flex justify-between items-center cursor-pointer hover:border-teal-500/50">
                        <div className="flex items-center gap-4">
                            <span className="text-[10px] font-black text-slate-600">#{i+1}</span>
                            <div>
                                <p className="text-sm font-black uppercase italic">{p.name}</p>
                                <p className="text-[9px] text-slate-500 font-bold uppercase">{p.nationality}</p>
                            </div>
                        </div>
                        <span className="text-lg font-black text-teal-400">{p.stat}</span>
                    </div>
                ))}
            </div>
        </div>
    );
};

