export const getPlayerById = (id: string, allPlayers: Player[]) => {
    const player = allPlayers.find(p => p.id === id);
    if (!player) {
      return { id: 'unknown', name: 'Unknown Player', role: PlayerRole.BATSMAN, battingSkill: 30, secondarySkill: 30, style: 'N' } as any as Player;
    }
    return player;
};

export const generateAutoXI = (squad: Player[], format: Format) => {
    const selectedPlayerIds = new Set<string>();
    const xi: Player[] = [];

    // Limits: Max 4, Min 2 Foreign
    let foreignInXI = 0;

    const addPlayer = (p: Player) => {
        if (selectedPlayerIds.has(p.id)) return false;
        if (p.isForeign && foreignInXI >= 4) return false;

        xi.push(p);
        selectedPlayerIds.add(p.id);
        if (p.isForeign) foreignInXI++;
        return true;
    };

    // 1. Must have a Wicket Keeper (Top priority)
    const keeper = [...squad].sort((a,b) => b.battingSkill - a.battingSkill).find(p => p.role === PlayerRole.WICKET_KEEPER);
    if (keeper) addPlayer(keeper);

    // 2. Add Required minimum 2 foreign players if possible
    if (foreignInXI < 2) {
        const bestForeign = squad.filter(p => p.isForeign && !selectedPlayerIds.has(p.id))
            .sort((a, b) => (b.battingSkill + b.secondarySkill) - (a.battingSkill + a.secondarySkill));

        while (foreignInXI < 2 && bestForeign.length > 0) {
            const p = bestForeign.shift();
            if (p) addPlayer(p);
        }
    }

    // 3. Fill with openers
    const openers = squad.filter(p => p.isOpener && !selectedPlayerIds.has(p.id))
        .sort((a,b) => b.battingSkill - a.battingSkill);
    openers.slice(0, 2).forEach(addPlayer);

    // 4. Fill main batsmen
    const batsmen = squad.filter(p => p.role === PlayerRole.BATSMAN && !selectedPlayerIds.has(p.id))
        .sort((a,b) => b.battingSkill - a.battingSkill);
    batsmen.forEach(p => { if (xi.length < 11) addPlayer(p); });

    // 5. Fill with All-rounders and Bowlers
    const others = squad.filter(p => !selectedPlayerIds.has(p.id))
        .sort((a,b) => b.secondarySkill - a.secondarySkill);
    others.forEach(p => { if (xi.length < 11) addPlayer(p); });

    return xi.slice(0, 11);
};

