export const calculatePlayerRankings = (players: Player[], format: Format, teams: Team[]) => {
    const scoredPlayers = players.map(p => {
        const stats = p.stats[format];
        const points = (stats.runs * 1) + (stats.wickets * 25) + (stats.manOfTheMatchAwards * 100);
        return { player: p, points, teamName: teams.find(t => t.squad.some(sp => sp.id === p.id))?.name || 'Free Agent' };
    }).sort((a,b) => b.points - a.points);
    return { batters: scoredPlayers, bowlers: scoredPlayers, allRounders: scoredPlayers };
};

import React, { useState, useEffect } from 'react';
import { AppState, GameData, Team, Player, Format, MatchResult } from './types';
