    status: 'toss' | 'ready' | 'inprogress' | 'inning_break' | 'completed'; match: Match; currentInningIndex: number; innings: Inning[]; target: number | null; currentBatters: { strikerId: string; nonStrikerId: string }; currentBowlerId: string; recentBalls: string[]; commentary: string[]; battingTeam: Team; bowlingTeam: Team; requiredRunRate: number; currentPartnership: { runs: number, balls: number }; fallOfWickets: { score: number, wicket: number, over: string, player: string }[]; waitingFor: 'openers' | 'batter' | 'bowler' | 'batter_arrival' | 'bowler_change' | null; strategies: { batting: Strategy; bowling: Strategy; }; autoPlayType: 'regular' | 'inning' | 'match' | null; tossWinnerId: string | null; tossDecision: 'bat' | 'bowl' | null;
}

export interface Message { id: string; text: string; sender: 'user' | 'model' | 'bot'; timestamp?: Date; }

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Player, Team, GameData, PlayerRole, Format } from '../types';
import { getRoleColor, getRoleFullName } from '../utils';
import { Icons } from './Icons';

interface AuctionRoomProps {
    gameData: GameData;
    onAuctionComplete: (updatedTeams: Team[]) => void;
}

const STARTING_PURSE = 50.0;
const MAX_SQUAD_LIMIT = 18;
const MIN_SQUAD_LIMIT = 16;
const MAX_FOREIGN_LIMIT = 7;
const MIN_FOREIGN_LIMIT = 4;
const MAX_LOCAL_LIMIT = 13;
const MIN_LOCAL_LIMIT = 10;

const shuffle = <T,>(array: T[]): T[] => {
    const newArr = [...array];
    for (let i = newArr.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [newArr[i], newArr[j]] = [newArr[j], newArr[i]];
    }
    return newArr;
};

const AuctionRoom: React.FC<AuctionRoomProps> = ({ gameData, onAuctionComplete }) => {
    const [teams, setTeams] = useState<Team[]>(() => 
        gameData.teams.map(t => ({ ...t, squad: [], purse: STARTING_PURSE }))
    );

    const [activeOverlay, setActiveOverlay] = useState<'none' | 'franchises' | 'pool'>('none');

    const sortedPool = useMemo(() => {
        const retainedPlayerIds = new Set(teams.flatMap(t => t.squad.map(p => p.id)));
        return gameData.allPlayers
            .filter(pl => !retainedPlayerIds.has(pl.id))
            .sort((a, b) => {
                const skillA = Math.max(a.battingSkill, a.secondarySkill);
                const skillB = Math.max(b.battingSkill, b.secondarySkill);
                const jitter = (Math.random() * 20) - 10;
                return (skillB + jitter) - (skillA + jitter);
            });
    }, [gameData.allPlayers, teams]);

    const [currentPlayerIdx, setCurrentPlayerIdx] = useState(0);
    const [currentBid, setCurrentBid] = useState(0);
    const [highestBidderId, setHighestBidderId] = useState<string | null>(null);
    const [isAuctioning, setIsAuctioning] = useState(false);
    const [biddingLog, setBiddingLog] = useState<string[]>([]);
    const [auctionFinished, setAuctionFinished] = useState(false);

    const currentPlayer = sortedPool[currentPlayerIdx] || null;
    const userTeam = teams.find(t => t.id === gameData.userTeamId);

    const getBasePrice = (player: Player) => {
        const attr = Math.max(player.battingSkill, player.secondarySkill);
        if (attr > 75) return 2.0;
        if (attr >= 65) return 1.0; 
        if (attr >= 50) return 0.5;
        return 0.2;
    };

    const startNextPlayer = useCallback(() => {
        if (auctionFinished) return;
        if (currentPlayerIdx >= sortedPool.length) {
            setAuctionFinished(true);
            return;
        }
        const player = sortedPool[currentPlayerIdx];
        if (!player) {
            setCurrentPlayerIdx(prev => prev + 1);
            return;
        }
        const bp = getBasePrice(player);
        setCurrentBid(bp);
        setHighestBidderId(null);
        setIsAuctioning(true);
        setBiddingLog(prev => [`Lot #${currentPlayerIdx + 1}: ${player.name} (${player.nationality}) up for ${bp.toFixed(2)} Cr`, ...prev.slice(0, 5)]);
    }, [currentPlayerIdx, sortedPool, auctionFinished]);

    const handleUserBid = () => {
        if (!userTeam || !isAuctioning || !currentPlayer) return;

        const foreignCount = userTeam.squad.filter(p => p.isForeign).length;
        const localCount = userTeam.squad.length - foreignCount;

        if (currentPlayer.isForeign && foreignCount >= MAX_FOREIGN_LIMIT) {
            setBiddingLog(prev => [`Foreign limit (${MAX_FOREIGN_LIMIT}) reached!`, ...prev.slice(0, 5)]);
            return;
        }
        if (!currentPlayer.isForeign && localCount >= MAX_LOCAL_LIMIT) {
            setBiddingLog(prev => [`Pakistani limit (${MAX_LOCAL_LIMIT}) reached!`, ...prev.slice(0, 5)]);
            return;
        }
        if (userTeam.squad.length >= MAX_SQUAD_LIMIT) {
             setBiddingLog(prev => [`Squad Full!`, ...prev.slice(0, 5)]);
             return;
        }

        const nextBid = Number((currentBid + 0.1).toFixed(2));
        if (userTeam.purse < nextBid) return;

        setCurrentBid(nextBid);
        setHighestBidderId(userTeam.id);
        setBiddingLog(prev => [`${userTeam.name} bids ${nextBid.toFixed(2)} Cr!`, ...prev.slice(0, 5)]);
    };

    const skipPlayer = () => {
        if (!currentPlayer || !isAuctioning) return;
        setIsAuctioning(false);
        setBiddingLog(prev => [`Unsold: ${currentPlayer.name}`, ...prev]);
        setTimeout(() => setCurrentPlayerIdx(prev => prev + 1), 200);
    };

    useEffect(() => {
        if (!isAuctioning || !currentPlayer || auctionFinished) return;
        const timer = setTimeout(() => {
            const eligibleTeams = teams.filter(t => 
                t.id !== highestBidderId && 
                t.purse >= (currentBid + 0.1) &&
                t.squad.length < MAX_SQUAD_LIMIT &&
                (!currentPlayer.isForeign || t.squad.filter(p => p.isForeign).length < MAX_FOREIGN_LIMIT) &&
                (currentPlayer.isForeign || (t.squad.length - t.squad.filter(p => p.isForeign).length) < MAX_LOCAL_LIMIT)
            );
            if (eligibleTeams.length > 0) {
                const rating = Math.max(currentPlayer.battingSkill, currentPlayer.secondarySkill);
                const biddingTeam = eligibleTeams.find(t => {
                    if (t.id === gameData.userTeamId) return false;
                    const val = (rating / 85) * 12.0 * (0.8 + Math.random() * 0.4); 
                    return (currentBid + 0.1) <= val;
                });
                if (biddingTeam) {
                    const nextBid = Number((currentBid + 0.1).toFixed(2));
                    setCurrentBid(nextBid);
                    setHighestBidderId(biddingTeam.id);
                    setBiddingLog(prev => [`${biddingTeam.name} bids ${nextBid.toFixed(2)} Cr!`, ...prev.slice(0, 5)]);
                } else if (highestBidderId) sellPlayer();
                else unsoldPlayer();
            } else if (highestBidderId) sellPlayer();
            else unsoldPlayer();
        }, 600);
        return () => clearTimeout(timer);
    }, [isAuctioning, currentBid, highestBidderId, currentPlayer, teams]);

    const sellPlayer = () => {
        setIsAuctioning(false);
        const winner = teams.find(t => t.id === highestBidderId);
        if (winner && currentPlayer) {
            setTeams(prev => prev.map(t => t.id === winner.id ? { ...t, purse: Number((t.purse - currentBid).toFixed(2)), squad: [...t.squad, currentPlayer] } : t));
            setBiddingLog(prev => [`SOLD! ${currentPlayer.name} to ${winner.name}`, ...prev]);
        }
        setTimeout(() => setCurrentPlayerIdx(prev => prev + 1), 600);
    };

    const unsoldPlayer = () => {
        setIsAuctioning(false);
        setBiddingLog(prev => [`UNSOLD: ${currentPlayer.name}`, ...prev]);
        setTimeout(() => setCurrentPlayerIdx(prev => prev + 1), 600);
    };

    useEffect(() => {
        if (!isAuctioning && !auctionFinished) startNextPlayer();
    }, [currentPlayerIdx, sortedPool, isAuctioning, auctionFinished, startNextPlayer]);

    const finishAuction = () => {
        const soldIds = new Set(teams.flatMap(t => t.squad.map(p => p.id)));
        let pool: Player[] = shuffle(gameData.allPlayers.filter(p => !soldIds.has(p.id)));

        const finalTeams = teams.map(team => {
            let squad = [...team.squad];
            let purse = team.purse;

            const fill = (foreign: boolean, min: number) => {
                /* Fix: Added explicit type Player to solve 'unknown' error on p.isForeign */
                let count = squad.filter((p: Player) => p.isForeign === foreign).length;
                while (count < min && pool.length > 0 && squad.length < MAX_SQUAD_LIMIT) {
                    /* Fix: Added explicit type Player to solve 'unknown' error on p.isForeign */
                    const idx = pool.findIndex((p: Player) => p.isForeign === foreign);
                    if (idx !== -1) {
                        squad.push(pool.splice(idx, 1)[0]);
                        count++;
                        purse = Math.max(0, purse - 0.2);
                    } else break;
                }
            };

            // Enforce Min Foreign (4) and Min Local (10)
            fill(true, MIN_FOREIGN_LIMIT);
            fill(false, MIN_LOCAL_LIMIT);

            // Fill to Min Squad Size (16) if still short
            while (squad.length < MIN_SQUAD_LIMIT && pool.length > 0) {
                 const fCount = squad.filter(p => p.isForeign).length;
                 const lCount = squad.length - fCount;
                 const canAddForeign = fCount < MAX_FOREIGN_LIMIT;
                 const canAddLocal = lCount < MAX_LOCAL_LIMIT;

                 /* Fix: Added explicit type Player to solve 'unknown' error on p.isForeign */
                 const idx = pool.findIndex((p: Player) => (p.isForeign && canAddForeign) || (!p.isForeign && canAddLocal));
                 if (idx !== -1) {
                    squad.push(pool.splice(idx, 1)[0]);
                    purse = Math.max(0, purse - 0.2);
                 } else break;
            }

            return { ...team, squad, purse };
        });

        onAuctionComplete(finalTeams);
    };

    return (
        <div className="h-full flex flex-col bg-[#020617] text-white font-sans overflow-hidden relative">
            <div className="bg-[#0f172a] p-4 pt-10 border-b border-slate-800 flex flex-col gap-2 shadow-2xl z-10">
                <div className="flex justify-between items-center">
                    <div className="flex items-center gap-2">
                        <div className="bg-pink-600 text-white px-2 py-0.5 rounded font-black text-xs skew-x-[-12deg]">AUCTION LIVE</div>
                        <h1 className="text-sm font-black text-slate-300 tracking-tight uppercase">SCRATCH START</h1>
                    </div>
                    <div className="text-right">
                        <span className="text-xl font-black text-teal-400">{userTeam?.purse?.toFixed(2) || '0.00'} Cr</span>
                        <p className="text-[9px] text-slate-500 font-bold uppercase tracking-widest leading-none">Your Purse</p>
                    </div>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 flex flex-col">
                {!auctionFinished ? (
                    <>
                        {currentPlayer && (
                            <div className="bg-slate-900/80 rounded-[2rem] border border-slate-800 shadow-2xl p-6 relative flex flex-col">
                                <div className="flex justify-between items-start mb-6">
                                    <div className={`px-2 py-0.5 rounded text-[10px] font-black uppercase ${getRoleColor(currentPlayer.role)} bg-opacity-20 border border-current`}>
                                        {getRoleFullName(currentPlayer.role)} {currentPlayer.isForeign ? '✈️' : '🇵🇰'}
                                    </div>
                                    <div className="text-[10px] text-slate-600 font-bold uppercase">Lot #{currentPlayerIdx + 1}</div>
                                </div>
                                <div className="text-center mb-8">
                                    <h2 className="text-4xl font-black italic uppercase tracking-tighter break-words leading-none mb-4">{currentPlayer.name}</h2>
                                    <p className="text-zinc-500 text-xs uppercase font-bold tracking-widest">{currentPlayer.nationality}</p>
                                </div>
                                <div className="bg-black/40 rounded-2xl p-4 mb-8 text-center border border-white/5">
                                    <span className="text-[10px] text-slate-500 uppercase font-black tracking-widest block mb-2">CURRENT BID</span>
                                    <div className="text-6xl font-black text-yellow-400 tabular-nums tracking-tighter">
                                        {currentBid.toFixed(2)} <span className="text-2xl ml-[-10px]">Cr</span>
                                    </div>
                                    <div className="mt-1 text-xs font-bold text-slate-400 uppercase tracking-widest truncate">
                                        {highestBidderId ? `Leading: ${teams.find(t => t.id === highestBidderId)?.name}` : 'Opening Bid'}
                                    </div>
                                </div>
                                <div className="flex flex-col gap-3">
                                    <button onClick={handleUserBid} disabled={!isAuctioning || (highestBidderId === userTeam?.id) || (userTeam?.purse || 0) < (currentBid + 0.1)} className={`w-full py-5 rounded-2xl font-black text-2xl italic uppercase tracking-tighter shadow-2xl transition-all transform active:scale-95 ${highestBidderId === userTeam?.id ? 'bg-emerald-900/40 border-2 border-emerald-500 text-emerald-400' : 'bg-teal-500 hover:bg-teal-400 text-black'} disabled:opacity-20`}>
                                        BID ({(currentBid + 0.1).toFixed(2)})
                                    </button>
                                    <div className="grid grid-cols-2 gap-3 mt-1">
                                        <button onClick={skipPlayer} className="bg-slate-900/60 hover:bg-slate-700 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest border border-white/5">Pass / Next</button>
                                        <button onClick={() => setAuctionFinished(true)} className="bg-red-950/40 hover:bg-red-900/60 border border-red-900/50 py-4 rounded-2xl text-[10px] font-black text-red-300 uppercase tracking-widest">Auto-Fill All</button>
                                    </div>
                                </div>
                            </div>
                        )}
                        <div className="mt-auto pt-6">
                            <div className="bg-black p-4 rounded-2xl h-32 overflow-y-auto border border-white/5 font-mono text-[10px]">
                                <div className="text-slate-600 mb-2 border-b border-white/10 pb-1 uppercase tracking-widest">Auction Log</div>
                                {biddingLog.map((log, i) => <div key={i} className={`mb-1 ${i === 0 ? 'text-teal-400 font-bold' : 'text-slate-500'}`}>{log}</div>)}
                            </div>
                        </div>
                    </>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-center px-4 animate-fade-in">
                        <div className="text-8xl mb-8">🏏</div>
                        <h2 className="text-4xl font-black italic tracking-tighter leading-none mb-4 uppercase text-pink-500">DRAFT COMPLETE</h2>
                        <p className="text-slate-400 mb-12 text-sm px-6">All franchises have filled their squads from the international and local pool. Rules applied: 18 total, min 4 foreign, max 7 foreign.</p>
                        <button onClick={finishAuction} className="w-full bg-pink-600 py-6 rounded-[2rem] text-xl font-black italic tracking-tighter uppercase shadow-[0_0_40px_rgba(236,72,153,0.3)] hover:bg-pink-500 transition-colors">
                            Enter Career Mode
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
};

