import React, { useState, useEffect } from 'react';
import { AppState, GameData, Team, Format, MatchResult } from './types';
import { PLAYERS, TEAMS, GROUNDS, INITIAL_SPONSORSHIPS, INITIAL_NEWS } from './data';
import { LoadingSpinner, generateLeagueSchedule } from './utils';

// Components
import { MainMenu, TeamSelection } from './components/GameComponents';
import CareerHub from './components/CareerHub';
import AuctionRoom from './components/AuctionRoom';

export const App = () => {
  const [appState, setAppState] = useState<AppState>('MAIN_MENU');
  const [gameData, setGameData] = useState<GameData | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [theme, setTheme] = useState<'light' | 'dark'>('dark');
  const [feedbackMessage, setFeedbackMessage] = useState<{ text: string; type: 'success' | 'error' } | null>(null);
  const [hasSaveData, setHasSaveData] = useState(false);

  useEffect(() => {
    const savedTheme = localStorage.getItem('cricketManagerTheme') || 'dark';
    setTheme(savedTheme as 'light' | 'dark');
    const savedGame = localStorage.getItem('cricketManagerSave');
    if (savedGame) {
        setHasSaveData(true);
    }
    setIsLoading(false);
  }, []);

  useEffect(() => {
    if (theme === 'light') {
        document.documentElement.classList.remove('dark');
    } else {
        document.documentElement.classList.add('dark');
    }
    localStorage.setItem('cricketManagerTheme', theme);
  }, [theme]);

  useEffect(() => {
    if (gameData && !isLoading) {
      localStorage.setItem('cricketManagerSave', JSON.stringify(gameData));
      setHasSaveData(true);
    }
  }, [gameData, isLoading]);

  const showFeedback = (text: string, type: 'success' | 'error' = 'success') => {
    setFeedbackMessage({ text, type });
    setTimeout(() => setFeedbackMessage(null), 2500);
  };

  const resumeGame = () => {
    const savedGame = localStorage.getItem('cricketManagerSave');
    if (savedGame) {
        try {
            setGameData(JSON.parse(savedGame));
            setAppState('CAREER_HUB');
            showFeedback("Game Resumed!", "success");
        } catch(e) {
            localStorage.removeItem('cricketManagerSave');
            setHasSaveData(false);
            showFeedback("Failed to load saved game.", "error");
        }
    }
  };

  const handleStartNewGame = () => {
    if (hasSaveData && !window.confirm("Starting a new game will overwrite your progress. Continue?")) {
        return;
    }
    setAppState('TEAM_SELECTION');
  };

  const initializeNewGame = (userTeamId: string) => {
    setIsLoading(true);
    const allPlayers = PLAYERS.map(p => JSON.parse(JSON.stringify(p)));
    const initialTeamsData = [...TEAMS];

    const initialTeams: Team[] = initialTeamsData.map(teamData => ({
        id: teamData.id, name: teamData.name, squad: [], captains: {}, purse: 50.0 
    }));

    const initialStandings = (teams: Team[]) => teams.map(team => ({ 
        teamId: team.id, teamName: team.name, played: 0, won: 0, lost: 0, drawn: 0, points: 0, netRunRate: 0, runsFor: 0, runsAgainst: 0 
    }));

    const schedules = {
        [Format.T20]: generateLeagueSchedule(initialTeams, Format.T20),
        [Format.ODI]: generateLeagueSchedule(initialTeams, Format.ODI),
        [Format.FIRST_CLASS]: generateLeagueSchedule(initialTeams, Format.FIRST_CLASS),
    };

    const newGameData: GameData = {
      userTeamId,
      teams: initialTeams,
      grounds: [...GROUNDS],
      allTeamsData: initialTeamsData,
      allPlayers,
      schedule: schedules,
      currentMatchIndex: { [Format.T20]: 0, [Format.ODI]: 0, [Format.FIRST_CLASS]: 0 },
      standings: { [Format.T20]: initialStandings(initialTeams), [Format.ODI]: initialStandings(initialTeams), [Format.FIRST_CLASS]: initialStandings(initialTeams) },
      matchResults: { [Format.T20]: [], [Format.ODI]: [], [Format.FIRST_CLASS]: [] },
      playingXIs: {},
      currentSeason: 1,
      currentFormat: Format.T20, 
      awardsHistory: [],
      records: { batterVsBowler: [], teamVsTeam: [], playerVsTeam: [] },
      promotionHistory: [],
      popularity: 50,
      sponsorships: INITIAL_SPONSORSHIPS,
      news: INITIAL_NEWS,
      activeMatch: null,
      settings: { isDoubleRoundRobin: true }
    };
    setGameData(newGameData);
    setAppState('AUCTION');
    setIsLoading(false);
  };

  const handleAuctionComplete = (finalTeams: Team[]) => {
      setGameData(prev => prev ? ({ ...prev, teams: finalTeams }) : null);
      setAppState('CAREER_HUB');
      showFeedback("Auction Complete! Let's play.", "success");
  };

  const renderContent = () => {
    if (isLoading) return <div className="h-full flex items-center justify-center bg-slate-900"><LoadingSpinner /></div>;
    switch(appState) {
        case 'MAIN_MENU': return <MainMenu onStartNewGame={handleStartNewGame} onResumeGame={resumeGame} hasSaveData={hasSaveData} />;
        case 'TEAM_SELECTION': return <TeamSelection onTeamSelected={initializeNewGame} theme={theme} />;
        case 'AUCTION': return gameData ? <AuctionRoom gameData={gameData} onAuctionComplete={handleAuctionComplete} /> : null;
        case 'CAREER_HUB': return gameData ? <CareerHub gameData={gameData} setGameData={setGameData} onResetGame={() => setAppState('MAIN_MENU')} theme={theme} setTheme={setTheme} saveGame={() => showFeedback("Saved!")} loadGame={resumeGame} showFeedback={showFeedback} /> : null;
        default: return null;
    }
  }

  return (
    <div className="bg-gray-100 dark:bg-gray-900 min-h-screen flex items-center justify-center font-sans">
      <div className="w-full max-w-md h-screen max-h-[932px] bg-gray-50 dark:bg-[#2C3531] border-4 border-gray-300 dark:border-gray-700 rounded-[60px] shadow-2xl shadow-black/50 overflow-hidden relative text-gray-900 dark:text-gray-200 flex flex-col">
        {renderContent()}
        {feedbackMessage && (
            <div className={`absolute bottom-28 left-1/2 -translate-x-1/2 px-4 py-2 rounded-lg z-50 shadow-lg text-white font-semibold ${feedbackMessage.type === 'success' ? 'bg-green-500' : 'bg-red-500'}`}>{feedbackMessage.text}</div>
        )}
      </div>
    </div>
  );
};

