export const generateAutoXI = (squad: Player[], format: Format) => {
    const xi: Player[] = [];
    const used = new Set<string>();
    let foreignInXI = 0;

    const add = (p: Player) => {
        if (used.has(p.id)) return false;
        if (p.isForeign && foreignInXI >= 4) return false;
        xi.push(p);
        used.add(p.id);
        if (p.isForeign) foreignInXI++;
        return true;
    };

    // 1. Mandatory Keeper
    const keeper = [...squad].sort((a,b) => b.battingSkill - a.battingSkill).find(p => p.role === PlayerRole.WICKET_KEEPER);
    if (keeper) add(keeper);

    // 2. Minimum 2 Foreign
    const bestForeign = squad.filter(p => p.isForeign && !used.has(p.id)).sort((a,b) => b.battingSkill - a.battingSkill);
    while (foreignInXI < 2 && bestForeign.length > 0) {
        const p = bestForeign.shift();
        if (p) add(p);
    }

    // 3. Openers
    squad.filter(p => p.isOpener && !used.has(p.id)).sort((a,b) => b.battingSkill - a.battingSkill).slice(0, 2).forEach(add);

    // 4. Best Batsmen
    squad.filter(p => p.role === PlayerRole.BATSMAN && !used.has(p.id)).sort((a,b) => b.battingSkill - a.battingSkill).forEach(p => { if (xi.length < 11) add(p); });

    // 5. Fill remaining slots with best skills
    squad.filter(p => !used.has(p.id)).sort((a,b) => (b.battingSkill + b.secondarySkill) - (a.battingSkill + a.secondarySkill)).forEach(p => { if (xi.length < 11) add(p); });

    return xi.slice(0, 11);
};

