export const generateLeagueSchedule = (teams: Team[], format: Format): Match[] => {
    const matches: Match[] = [];
    if (teams.length < 2) return [];
    for(let i=0; i<teams.length; i++) {
        for(let j=i+1; j<teams.length; j++) {
            matches.push({ matchNumber: matches.length+1, teamA: teams[i].name, teamAId: teams[i].id, vs: 'vs', teamB: teams[j].name, teamBId: teams[j].id, date: `Match Day ${matches.length+1}`, group: 'Round-Robin' });
            matches.push({ matchNumber: matches.length+1, teamA: teams[j].name, teamAId: teams[j].id, vs: 'vs', teamB: teams[i].name, teamBId: teams[i].id, date: `Match Day ${matches.length+1}`, group: 'Round-Robin' });
        }
    }
    return matches;
};

